import * as React from "react"

import { cn } from "@/lib/utils"

const Card = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => (
  <div
    ref={ref}
    className={cn(
      "rounded-lg border-[1.5px] border-border-primary bg-background-primary text-card-foreground overflow-hidden",
      className
    )}
    {...props}
  />
))
Card.displayName = "Card"

